<?php if (!defined('ABSPATH')) exit; get_header(); while (have_posts()) : the_post(); $autor = get_post_meta(get_the_ID(), '_autor', true); $isbn = get_post_meta(get_the_ID(), '_isbn', true); $editorial = get_post_meta(get_the_ID(), '_editorial', true); $anio = get_post_meta(get_the_ID(), '_anio_publicacion', true); $disponible = get_post_meta(get_the_ID(), '_disponible', true); ?>
<div class="flavor-container py-8"><div class="grid lg:grid-cols-3 gap-8"><div class="lg:col-span-1"><?php if (has_post_thumbnail()) the_post_thumbnail('large', array('class' => 'w-full rounded-xl shadow-lg')); ?></div><div class="lg:col-span-2"><h1 class="text-4xl font-bold mb-4"><?php the_title(); ?></h1><?php if ($autor) : ?><p class="text-xl text-gray-600 mb-6">por <?php echo esc_html($autor); ?></p><?php endif; ?><div class="mb-6"><?php echo $disponible ? '<span class="bg-green-100 text-green-700 px-4 py-2 rounded-lg font-semibold">Disponible para préstamo</span>' : '<span class="bg-red-100 text-red-700 px-4 py-2 rounded-lg font-semibold">Actualmente prestado</span>'; ?></div><div class="prose mb-8"><?php the_content(); ?></div><div class="bg-gray-50 rounded-lg p-6 mb-6"><h3 class="text-lg font-bold mb-4">Información del libro</h3><dl class="space-y-3"><?php if ($editorial) : ?><div><dt class="text-sm font-semibold">Editorial:</dt><dd><?php echo esc_html($editorial); ?></dd></div><?php endif; ?><?php if ($anio) : ?><div><dt class="text-sm font-semibold">Año:</dt><dd><?php echo esc_html($anio); ?></dd></div><?php endif; ?><?php if ($isbn) : ?><div><dt class="text-sm font-semibold">ISBN:</dt><dd><?php echo esc_html($isbn); ?></dd></div><?php endif; ?></dl></div><?php if (is_user_logged_in() && $disponible) : ?><button class="px-8 py-4 bg-primary text-white rounded-lg hover:bg-primary-dark font-bold text-lg">Solicitar Préstamo</button><?php elseif (!is_user_logged_in()) : ?><a href="<?php echo wp_login_url(get_permalink()); ?>" class="inline-block px-8 py-4 bg-primary text-white rounded-lg font-bold text-lg">Inicia sesión</a><?php endif; ?></div></div></div><?php endwhile; get_footer(); ?>
